              </span>
              <span className="text-xs text-muted-foreground ml-auto">
                {new Date(l.created_at).toLocaleString()}
                {l.duration_ms != null && ` · ${l.duration_ms}ms`}
              </span>
            </div>
            {l.error && <p className="text-xs text-destructive mt-2">{l.error}</p>}
          </div>
        ))}
      </div>
    </div>
  );
}

