// Distribution registry — parent CMS side.
// Manages cms_releases, cms_migration_manifest, child_installations, child_upgrade_log.
// Children call the cms-release edge function to bootstrap; admins use this lib
// from the Releases / Installations / Upgrade Log pages.

import { supabase as cloud } from "@/integrations/supabase/client";
import { logActivity } from "@/lib/activityLog";

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const db = cloud as any;

export type Release = {
  id: string;
  version: string;
  sdk_url: string | null;
  package_url: string | null;
  package_sha256: string | null;
  package_size: number | null;
  package_format: string | null;
  bundle_url: string | null;
  bundle_sha256: string | null;
  bundle_css_url: string | null;
  bundle_size: number | null;
  manifest: Record<string, unknown>;
  changelog: string | null;
  min_compatible_child_version: string | null;
  is_latest: boolean;
  recalled: boolean;
  signature: string | null;
  signing_key_id: string | null;
  payload_hash: string | null;
  signed_at: string | null;
  published_at: string;
  created_at: string;
  updated_at: string;
};

export type MigrationStep = {
  id: string;
  version: string;
  order_index: number;
  kind: "sql" | "js" | "noop";
  description: string | null;
  payload: string;
  reversible: boolean;
  down_payload: string | null;
  created_at: string;
};

export type ChildInstallation = {
  id: string;
  site_id: string;
  site_name: string | null;
  site_url: string | null;
  current_version: string | null;
  child_shim_version: string | null;
  upgrade_state:
    | "unknown" | "up_to_date" | "pending" | "upgrading" | "failed" | "rolled_back";
  last_error: string | null;
  last_seen_at: string | null;
  created_at: string;
  updated_at: string;
};

export type UpgradeLog = {
  id: string;
  site_id: string;
  from_version: string | null;
  to_version: string;
  status: "started" | "success" | "failed" | "rolled_back";
  snapshot: unknown;
  error: string | null;
  duration_ms: number | null;
  created_at: string;
};

/* ---------------- Releases ---------------- */

export async function listReleases(): Promise<Release[]> {
  const { data, error } = await db.from("cms_releases").select("*").order("created_at", { ascending: false });
  if (error) throw error;
  return (data || []) as Release[];
}

export async function getLatestRelease(): Promise<Release | null> {
  const { data } = await db
    .from("cms_releases")
    .select("*")
    .eq("is_latest", true)
    .eq("recalled", false)
    .maybeSingle();
  return (data || null) as Release | null;
}

export async function getRelease(version: string): Promise<Release | null> {
  const { data } = await db.from("cms_releases").select("*").eq("version", version).maybeSingle();
  return (data || null) as Release | null;
}

function semverCmp(a: string, b: string): number {
  const pa = a.split("-")[0].split(".").map((n) => parseInt(n, 10) || 0);
  const pb = b.split("-")[0].split(".").map((n) => parseInt(n, 10) || 0);
  for (let i = 0; i < 3; i++) {
    const d = (pa[i] || 0) - (pb[i] || 0);
    if (d !== 0) return d;
  }
  return 0;
}

export async function cutRelease(input: {
  version: string;
  changelog?: string;
  sdk_url?: string;
  package_url?: string;
  package_sha256?: string;
  package_size?: number;
  package_format?: string;
  manifest?: Record<string, unknown>;
  min_compatible_child_version?: string;
  migrations?: Array<Omit<MigrationStep, "id" | "version" | "created_at"> & { migration_id?: string }>;
}): Promise<Release> {
  if (!/^\d+\.\d+\.\d+([.-][0-9A-Za-z.-]+)?$/.test(input.version)) {
    throw new Error(`Version "${input.version}" is not semver (X.Y.Z).`);
  }
  // Client-side forward-only check (DB also enforces, but fail fast for UX).
  const { data: top } = await db
    .from("cms_releases").select("version")
    .order("created_at", { ascending: false }).limit(50);
  for (const r of (top || []) as Array<{ version: string }>) {
    if (semverCmp(input.version, r.version) <= 0) {
      throw new Error(`Forward-only: ${input.version} must be strictly greater than ${r.version}.`);
    }
  }

  const { data, error } = await db
    .from("cms_releases")
    .insert({
      version: input.version,
      changelog: input.changelog || null,
      sdk_url: input.sdk_url || null,
      package_url: input.package_url || null,
      package_sha256: input.package_sha256 || null,
      package_size: input.package_size ?? null,
      package_format: input.package_format || "zip",
      manifest: input.manifest || {},
      min_compatible_child_version: input.min_compatible_child_version || null,
      is_latest: false,
      recalled: false,
    })
    .select("*")
    .single();
  if (error) throw error;

  await db.from("cms_releases").update({ is_latest: false }).eq("is_latest", true);
  const { error: promoteError } = await db.from("cms_releases").update({ is_latest: true }).eq("id", data.id);
  if (promoteError) throw promoteError;
  data.is_latest = true;

  if (input.migrations?.length) {
    const rows = input.migrations.map((m, i) => ({
      version: input.version,
      migration_id: m.migration_id || `${input.version}:${m.order_index ?? i}`,
      order_index: m.order_index ?? i,
      kind: m.kind,
      description: m.description ?? null,
      payload: m.payload || "",
      reversible: !!m.reversible,
      down_payload: m.down_payload ?? null,
    }));
    const { error: migrationError } = await db.from("cms_migration_manifest").insert(rows);
    if (migrationError) throw migrationError;
  }

  await logActivity({
    action: "create",
    entity_type: "cms_release",
    entity_id: data.id,
    entity_label: `Cut release v${input.version}`,
    details: { version: input.version, migrations: input.migrations?.length || 0 },
  });

  return data as Release;
}

export async function recallRelease(id: string, recall: boolean): Promise<void> {
  const { data } = await db.from("cms_releases").select("version").eq("id", id).single();
  await db.from("cms_releases").update({ recalled: recall }).eq("id", id);
  if (recall) {
    // Promote the most recent non-recalled to latest
    await db.from("cms_releases").update({ is_latest: false }).eq("id", id);
    const { data: next } = await db
      .from("cms_releases")
      .select("id")
      .eq("recalled", false)
      .order("published_at", { ascending: false })
      .limit(1)
      .maybeSingle();
    if (next?.id) await db.from("cms_releases").update({ is_latest: true }).eq("id", next.id);
  }
  await logActivity({
    action: recall ? "delete" : "restore",
    entity_type: "cms_release",
    entity_id: id,
    entity_label: `${recall ? "Recalled" : "Restored"} release v${data?.version || ""}`,
  });
}

export async function promoteRelease(id: string): Promise<void> {
  await db.from("cms_releases").update({ is_latest: false }).eq("is_latest", true);
  await db.from("cms_releases").update({ is_latest: true, recalled: false }).eq("id", id);
  await logActivity({
    action: "update",
    entity_type: "cms_release",
    entity_id: id,
    entity_label: "Promoted release to latest",
  });
}

/* ---------------- Migrations ---------------- */

export async function listMigrationsForVersion(version: string): Promise<MigrationStep[]> {
  const { data } = await db
    .from("cms_migration_manifest")
    .select("*")
    .eq("version", version)
    .order("order_index");
  return (data || []) as MigrationStep[];
}

/* ---------------- Installations ---------------- */

export async function listInstallations(): Promise<ChildInstallation[]> {
  const { data } = await db
    .from("child_installations")
    .select("*")
    .order("last_seen_at", { ascending: false, nullsFirst: false });
  return (data || []) as ChildInstallation[];
}

export async function forceUpgrade(site_id: string, to_version: string): Promise<void> {
  await db
    .from("child_installations")
    .update({ upgrade_state: "pending" })
    .eq("site_id", site_id);
  await logActivity({
    action: "update",
    entity_type: "child_installation",
    entity_id: site_id,
    entity_label: `Queued force-upgrade to v${to_version}`,
    details: { to_version },
  });
}

/* ---------------- Upgrade log ---------------- */

export async function listUpgradeLog(site_id?: string, limit = 200): Promise<UpgradeLog[]> {
  let q = db.from("child_upgrade_log").select("*").order("created_at", { ascending: false }).limit(limit);
  if (site_id) q = q.eq("site_id", site_id);
  const { data } = await q;
  return (data || []) as UpgradeLog[];
}

files.src/lib/elementorImport.ts:
// Elementor "Site Kit" / Pro page importer.
// Parses a ZIP (manifest.json + wp-content/*.xml + content/{type}/{id}.json
// + templates/*.json + site-settings.json) and upserts into Lovable Cloud.
//
// Strategy:
//  - Pages/posts with an entry in the WP XML get upserted into `imported_posts`
//    by slug (update existing). Their Elementor tree lives on `elementor_data`.
//  - Every templates/*.json + every content/*.json that has NO matching XML
//    item is stored as a reusable item in `elementor_templates`.
//  - site-settings.json is stored once in `elementor_site_settings`.

import JSZip from "jszip";
import { supabase } from "@/integrations/supabase/client";

export type ElementorImportResult = {
  pages: number;
  posts: number;
  templates: number;
  sectionsLibrary: number;
  siteSettings: boolean;
  skipped: number;
  failed: number;
  errors: string[];
};

type WpItem = {
  postId: string;
  postType: string;
  postName: string;
  title: string;
  status: string;
  pubDate: string;
  link: string;
  content: string;
  excerpt: string;
  featuredImageUrl: string;
  meta: Record<string, string>;
};

const slugify = (s: string) =>
  (s || "")
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");

// -------- WP XML parsing (CDATA-aware, regex tolerant) ----------------------

function grab(block: string, tag: string): string {
  const re = new RegExp(
    `<${tag}[^>]*>\\s*(?:<!\\[CDATA\\[([\\s\\S]*?)\\]\\]>|([\\s\\S]*?))\\s*</${tag}>`,
    "i",
  );
  const m = block.match(re);
  return (m?.[1] ?? m?.[2] ?? "").trim();
}

function parseWpXml(xml: string): WpItem[] {
  const items: WpItem[] = [];
  const attachments: Record<string, string> = {};
  const itemRe = /<item\b[\s\S]*?<\/item>/g;
  const blocks = xml.match(itemRe) || [];

  for (const b of blocks) {
    if (grab(b, "wp:post_type") === "attachment") {
      const id = grab(b, "wp:post_id");
      const url = grab(b, "wp:attachment_url");
      if (id && url) attachments[id] = url;
    }
  }

  for (const b of blocks) {
    const postType = grab(b, "wp:post_type");
    if (postType === "attachment" || postType === "nav_menu_item" || !postType) continue;

    const meta: Record<string, string> = {};
    let featured = "";
    const metaBlocks = b.match(/<wp:postmeta\b[\s\S]*?<\/wp:postmeta>/g) || [];
    for (const mb of metaBlocks) {
      const k = grab(mb, "wp:meta_key");
      const v = grab(mb, "wp:meta_value");
      if (k) meta[k] = v;
      if (k === "_thumbnail_id" && attachments[v]) featured = attachments[v];
    }

    const title = grab(b, "title");
    const postName = grab(b, "wp:post_name") || slugify(title);
    items.push({
      postId: grab(b, "wp:post_id"),
      postType,
      postName,
      title,
      status: grab(b, "wp:status") || "publish",
      pubDate: grab(b, "wp:post_date") || grab(b, "pubDate"),
      link: grab(b, "link"),
      content: grab(b, "content:encoded"),
      excerpt: grab(b, "excerpt:encoded"),
      featuredImageUrl: featured,
      meta,
    });
  }
  return items;
}

// -------- Main importer -----------------------------------------------------

export async function importElementorZip(
  file: File,
  onProgress?: (msg: string) => void,
): Promise<ElementorImportResult> {
  const result: ElementorImportResult = {
    pages: 0,
    posts: 0,
    templates: 0,
    sectionsLibrary: 0,
    siteSettings: false,
    skipped: 0,
    failed: 0,
    errors: [],
  };

  const { data: sess } = await supabase.auth.getSession();
  const userId = sess?.session?.user?.id || null;
  if (!userId) throw new Error("Sign in required for Elementor import.");

  onProgress?.("Unzipping…");
  const zip = await JSZip.loadAsync(file);

  // 1. site-settings.json
  const settingsFile = zip.file("site-settings.json");
  if (settingsFile) {
    try {
      const json = JSON.parse(await settingsFile.async("string"));
      const { error } = await supabase
        .from("elementor_site_settings")
        .upsert(
          {
            source_id: "default",
            title: json.title || null,
            settings: json.settings || {},
            theme: json.theme || {},
          },
          { onConflict: "source_id" },
        );
      if (!error) result.siteSettings = true;
      else result.errors.push(`site-settings: ${error.message}`);
    } catch (e) {
      result.errors.push(`site-settings parse: ${(e as Error).message}`);
    }
  }

  // 2. Collect XML metadata indexed by post id
  type PostMeta = { item: WpItem; type: string };
  const metaById = new Map<string, PostMeta>();
  const xmlFiles = Object.keys(zip.files).filter((p) => p.match(/^wp-content\/[^/]+\/[^/]+\.xml$/));
  for (const path of xmlFiles) {
    const xml = await zip.files[path].async("string");
    const items = parseWpXml(xml);
    const typeDir = path.split("/")[1]; // e.g. page / post / case-study
    for (const it of items) {
      if (it.postId) metaById.set(it.postId, { item: it, type: typeDir });
    }
  }

  // 3. content/{type}/{id}.json — pages/posts/case-studies
  const contentFiles = Object.keys(zip.files).filter((p) =>
    p.match(/^content\/[^/]+\/\d+\.json$/),
  );

  const PAGE_LIKE = new Set(["page", "case-study"]);
  const POST_LIKE = new Set(["post"]);

  for (const path of contentFiles) {
    try {
      const parts = path.split("/"); // ["content", type, "{id}.json"]
      const typeDir = parts[1];
      const fileId = parts[2].replace(/\.json$/, "");
      const raw = await zip.files[path].async("string");
      const parsed = JSON.parse(raw);
      const elementorTree = Array.isArray(parsed.content) ? parsed.content : [];
      const settings = parsed.settings || {};

      const meta = metaById.get(fileId);

      if (!meta) {
        // No XML metadata → treat as reusable template/section
        const { error } = await supabase
          .from("elementor_templates")
          .upsert(
            {
              source_id: `content-${typeDir}-${fileId}`,
              kind: typeDir,
              title: `${typeDir} ${fileId}`,
              slug: `${typeDir}-${fileId}`,
              data: elementorTree,
              settings,
              source: "elementor",
              imported_by: userId,
            },
            { onConflict: "source_id" },
          );
        if (error) {
          result.failed++;
          result.errors.push(`content/${typeDir}/${fileId}: ${error.message}`);
        } else {
          result.sectionsLibrary++;
        }
        continue;
      }

      // Has XML metadata → upsert into imported_posts by slug
      const it = meta.item;
      const postType = POST_LIKE.has(typeDir) ? "post" : "page";
      const slug = it.postName || slugify(it.title) || `elementor-${fileId}`;
      const row = {
        site_id: (window as unknown as { __PL_SITE_ID?: string }).__PL_SITE_ID || "default",
        title: it.title || `Untitled ${fileId}`,
        slug,
        excerpt: it.excerpt || "",
        body: it.content || "",
        elementor_data: elementorTree as unknown as never,
        render_mode: postType === "post" ? "template" : "elementor",
        status: it.status === "publish" ? "published" : it.status === "draft" ? "draft" : "draft",
        publish_date: it.pubDate ? new Date(it.pubDate.replace(" ", "T")).toISOString() : null,
        featured_image_url: it.featuredImageUrl || null,
        type: postType,
        meta_title:
          it.meta["_yoast_wpseo_title"] ||
          it.meta["rank_math_title"] ||
          it.meta["_aioseo_title"] ||
          it.meta["_aioseop_title"] ||
          it.meta["_seopress_titles_title"] ||
          it.title,
        meta_description:
          it.meta["_yoast_wpseo_metadesc"] ||
          it.meta["rank_math_description"] ||
          it.meta["_aioseo_description"] ||
          it.meta["_aioseop_description"] ||
          it.meta["_seopress_titles_desc"] ||
          it.excerpt ||
          "",
        canonical_url:
          it.meta["_yoast_wpseo_canonical"] ||
          it.meta["rank_math_canonical_url"] ||
          it.meta["_aioseo_canonical_url"] ||
          it.meta["_seopress_robots_canonical"] ||
          it.link,
        source: "elementor",
        imported_by: userId,
        raw: { wp_post_id: fileId, meta: it.meta, kind: typeDir } as unknown as never,
      };
      const { error } = await supabase
        .from("imported_posts")
        .upsert(row, { onConflict: "site_id,slug" });
      if (error) {
        result.failed++;
        result.errors.push(`${slug}: ${error.message}`);
      } else if (postType === "post") {
        result.posts++;
      } else {
        result.pages++;
      }
    } catch (e) {
      result.failed++;
      result.errors.push(`${path}: ${(e as Error).message}`);
    }
  }

  // 4. templates/*.json — always reusable templates
  const templateFiles = Object.keys(zip.files).filter((p) => p.match(/^templates\/\d+\.json$/));
  onProgress?.(`Saving ${templateFiles.length} templates…`);
  for (const path of templateFiles) {
    try {
      const fileId = path.split("/")[1].replace(/\.json$/, "");
      const parsed = JSON.parse(await zip.files[path].async("string"));
      const elementorTree = Array.isArray(parsed.content) ? parsed.content : [];
      const settings = parsed.settings || {};
      const location = parsed.location || (parsed.metadata && parsed.metadata.type) || null;
      const { error } = await supabase
        .from("elementor_templates")
        .upsert(
          {
            source_id: `template-${fileId}`,
            kind: "template",
            title: `Template ${fileId}`,
            slug: `template-${fileId}`,
            data: elementorTree,
            settings,
            location,
            source: "elementor",
            imported_by: userId,
          },
          { onConflict: "source_id" },
        );
      if (error) {
        result.failed++;
        result.errors.push(`templates/${fileId}: ${error.message}`);
      } else {
        result.templates++;
      }
    } catch (e) {
      result.failed++;
      result.errors.push(`${path}: ${(e as Error).message}`);
    }
  }

  return result;
}

