CREATE OR REPLACE FUNCTION public.cms_releases_forward_only()
RETURNS TRIGGER
LANGUAGE plpgsql
SET search_path = public
AS $$
DECLARE
  _max TEXT;
BEGIN
  IF NEW.version !~ '^[0-9]+\.[0-9]+\.[0-9]+([.-][0-9A-Za-z.-]+)?$' THEN
    RAISE EXCEPTION 'version % is not semver (X.Y.Z)', NEW.version;
